 1	import React, { FC } from 'react';
 2	import { Trans } from 'react-i18next';
 3	import { Link } from 'react-router-dom-v5-compat';
 4	
 5	import { UseInstanceTypeAndPreferencesValues } from '@catalog/CreateFromInstanceTypes/state/utils/types';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { Popover, PopoverPosition } from '@patternfly/react-core';
 8	import { HelpIcon } from '@patternfly/react-icons';
 9	
10	import AddBootableVolumeLink from '../AddBootableVolumeLink/AddBootableVolumeLink';
11	
12	type CreateFromInstanceTypeTitleProps = {
13	  instanceTypesAndPreferencesData: UseInstanceTypeAndPreferencesValues;
14	};
15	
16	const CreateFromInstanceTypeTitle: FC<CreateFromInstanceTypeTitleProps> = ({
17	  instanceTypesAndPreferencesData,
18	}) => {
19	  const { t } = useKubevirtTranslation();
20	
21	  return (
22	    <>
23	      {t('Select volume to boot from')}{' '}
24	      <Popover
25	        bodyContent={(hide) => (
26	          <>
27	            <Trans ns="plugin__kubevirt-plugin" t={t}>
28	              <div>
29	                From the Volume table, select a bootable volume to boot your VirtualMachine.
30	              </div>
31	              <div>
32	                To add a bootable volume that is not listed, click{' '}
33	                <AddBootableVolumeLink
34	                  hidePopover={hide}
35	                  loadError={instanceTypesAndPreferencesData.loadError}
36	                  text={t('Add volume.')}
37	                />
38	              </div>
39	              <div>
40	                Learn how to{' '}
41	                <Link to="/quickstart?quickstart=windows-bootsource-pipeline">
42	                  create a bootable volume automatically by using pipelines
43	                </Link>
44	              </div>
45	            </Trans>
46	          </>
47	        )}
48	        className="create-vm-instance-type-section__HelpTextIcon"
49	        position={PopoverPosition.right}
50	      >
51	        <HelpIcon className="help-icon__cursor" />
52	      </Popover>
53	    </>
54	  );
55	};
56	
57	export default CreateFromInstanceTypeTitle;

